INSERT OR IGNORE INTO extractions (id, policy_id, company_id, facts_json, score, letter, grade_label, grade_color, rubric_version, breakdown_json, model, input_tokens, output_tokens, latency_ms, chunked, created_at) VALUES (8, 8, 8, '{"metadata":{"schemaVersion":"1.0.0","companyName":"Telegram (Telegram Messenger)","policyUrl":"https://telegram.org/privacy","analyzedAt":"2026-03-21T06:17:13.655Z","policyHash":"525ed5ea67f0542b1f8753c3698b7dfe0c57cd0ee842ffa0022f08f8185b41e6","policyEffectiveDate":"Updated September 29, 2024"},"dataCollection":{"items":[{"name":"Mobile phone number","sensitive":true,"sourceQuote":"You provide your mobile number and basic account data"},{"name":"Profile name and picture","sensitive":false,"sourceQuote":"basic account data (which may include profile name, profile picture and about information)"},{"name":"Email address","sensitive":true,"sourceQuote":"you can opt to set up a password recovery email"},{"name":"Messages and media","sensitive":true,"sourceQuote":"We store messages, photos, videos and documents from your cloud chats on our servers"},{"name":"Contacts list","sensitive":true,"sourceQuote":"We store your up-to-date contacts"},{"name":"IP address","sensitive":true,"sourceQuote":"we may collect metadata such as your IP address"},{"name":"Device information","sensitive":false,"sourceQuote":"devices and Telegram apps you''ve used"},{"name":"Username change history","sensitive":false,"sourceQuote":"history of username changes"},{"name":"Call logs","sensitive":true,"sourceQuote":"Telegram will ask you for permission to access your phone call logs (READ_CALL_LOG)"}],"collectsPreciseGeolocation":{"value":true,"confidence":0.95,"sourceQuote":"If you share your Live Location in any chat or turn on ''Make Myself Visible'' in People Nearby, Telegram will use your data to display your location"},"collectsBiometricData":{"value":false,"confidence":0.8,"sourceQuote":"Policy does not mention collection of biometric data such as fingerprints or face recognition"},"collectsHealthData":{"value":false,"confidence":0.8,"sourceQuote":"Policy does not mention collection of health or medical data"},"collectsFinancialData":{"value":false,"confidence":0.9,"sourceQuote":"Your credit card information never reaches Telegram''s servers. We do not access and do not store your credit card information"}},"dataSharing":{"soldToThirdParties":{"value":false,"confidence":0.95,"sourceQuote":"We don''t use your data to show you ads... Unlike other services, we don''t use your data for ad targeting or other commercial purposes"},"sharedForAdvertising":{"value":false,"confidence":0.9,"sourceQuote":"We don''t use your data for ad targeting or other commercial purposes... No user data is mined or analyzed to display ads or sponsored messages"},"crossSiteTracking":{"value":false,"confidence":0.85,"sourceQuote":"The only cookies we use are those to operate and provide our Services on the web. We do not use cookies for profiling or advertising"},"usedForProfiling":{"value":true,"confidence":0.8,"sourceQuote":"we calculate a rating that shows which people you message frequently. A similar rating is calculated for inline bots"},"usedToTrainAI":{"value":false,"confidence":0.7,"sourceQuote":"Policy mentions using data to ''build useful features'' and ''improve services'' but does not explicitly mention AI training"},"thirdPartyCount":6},"retention":{"retentionDays":null,"indefinite":false,"sourceQuote":"the personal data that you provide us will only be stored for as long as it is necessary for us to fulfill our obligations in respect of the provision of the Services... By default, if you stop using Telegram and do not come online for at least 18 months, your account will be deleted"},"consumerRights":{"rightToAccess":{"value":true,"confidence":0.95,"sourceQuote":"You have a right to: (1) request a copy of all your personal data that we store and to transmit that copy to another data controller"},"rightToDelete":{"value":true,"confidence":0.95,"sourceQuote":"If you would like to delete your account, you can do this on the deactivation page. Deleting your account removes all messages, media, contacts and every other piece of data you store in the Telegram cloud"},"rightToPortability":{"value":true,"confidence":0.95,"sourceQuote":"request a copy of all your personal data that we store and to transmit that copy to another data controller"},"rightToCorrect":{"value":true,"confidence":0.95,"sourceQuote":"You have a right to... correct any inaccurate or incomplete personal data we hold on you"},"rightToOptOut":{"value":true,"confidence":0.8,"sourceQuote":"You can control how your data is used (e.g., delete synced contacts) in Settings > Privacy & Security > Data Settings"},"rightToNonDiscrimination":{"value":false,"confidence":0.4,"sourceQuote":"Policy does not explicitly mention right to non-discrimination"}},"signalHonoring":{"honorsGPC":{"value":false,"confidence":0.4,"sourceQuote":"Policy does not mention Global Privacy Control (GPC). Defaulting to not honored"},"honorsDNT":{"value":false,"confidence":0.4,"sourceQuote":"Policy does not mention Do Not Track (DNT). Defaulting to not honored"}},"security":{"measures":[{"name":"End-to-end encryption for secret chats","sourceQuote":"Secret chats use end-to-end encryption. This means that all data is encrypted with a key that only you and the recipient know"},{"name":"Heavy encryption for cloud data","sourceQuote":"All data is stored heavily encrypted and the encryption keys in each case are stored in several other data centers in different jurisdictions"},{"name":"Distributed key storage","sourceQuote":"the encryption keys in each case are stored in several other data centers in different jurisdictions. This way local engineers or physical intruders cannot get access to user data"},{"name":"Server-side encryption","sourceQuote":"All data is stored heavily encrypted so that local Telegram engineers or physical intruders cannot get access"}]}}', 90, 'A', 'Excellent', '#15803d', '1', '[{"key":"soldToThirdParties","label":"Data sold to third parties","points":0,"triggered":false},{"key":"sharedForAdvertising","label":"Data shared for advertising","points":0,"triggered":false},{"key":"crossSiteTracking","label":"Cross-site tracking","points":0,"triggered":false},{"key":"usedForProfiling","label":"Used for profiling / AI decisions","points":-8,"triggered":true},{"key":"usedToTrainAI","label":"Used to train AI models","points":0,"triggered":false},{"key":"collectsPreciseGeolocation","label":"Collects precise geolocation","points":-8,"triggered":true},{"key":"collectsBiometricData","label":"Collects biometric data","points":0,"triggered":false},{"key":"collectsHealthData","label":"Collects health data","points":0,"triggered":false},{"key":"collectsFinancialData","label":"Collects financial data","points":0,"triggered":false},{"key":"doesNotHonorGPC","label":"Does not honor GPC","points":-5,"triggered":true},{"key":"doesNotHonorDNT","label":"Does not honor DNT","points":-2,"triggered":true},{"key":"thirdPartiesOver10","label":"More than 10 third parties","points":0,"triggered":false,"detail":"6 third parties disclosed"},{"key":"thirdParties6To10","label":"6–10 third parties","points":-5,"triggered":true,"detail":"6 third parties disclosed"},{"key":"retentionIndefinite","label":"Retention is indefinite","points":0,"triggered":false},{"key":"retentionOver3Years","label":"Retention longer than 3 years","points":0,"triggered":false},{"key":"retentionOver1Year","label":"Retention longer than 1 year","points":0,"triggered":false},{"key":"consumerRights","label":"Consumer rights available","points":10,"triggered":true,"detail":"5 of 6 rights offered"},{"key":"securityMeasures","label":"Security measures in place","points":8,"triggered":true,"detail":"4 of 5 measures"}]', 'claude-sonnet-4-20250514', 9550, 1769, 32543, 0, '2026-03-21T06:17:46Z');
INSERT OR IGNORE INTO extractions (id, policy_id, company_id, facts_json, score, letter, grade_label, grade_color, rubric_version, breakdown_json, model, input_tokens, output_tokens, latency_ms, chunked, created_at) VALUES (9, 9, 9, '{"metadata":{"schemaVersion":"1.0.0","companyName":"Discord Inc.","policyUrl":"https://discord.com/privacy","analyzedAt":"2026-03-21T06:17:13.641Z","policyHash":"a40c66cb71b83933815dabe1a98fdd40d7248b5016170d04b9f8c118c8f17162","policyEffectiveDate":"September 29, 2025"},"dataCollection":{"items":[{"name":"username","sensitive":false,"sourceQuote":"When you create a Discord account, you can come up with a username and password"},{"name":"password","sensitive":true,"sourceQuote":"When you create a Discord account, you can come up with a username and password"},{"name":"email","sensitive":false,"sourceQuote":"provide a way of contacting you (such as an email address and/or phone number)"},{"name":"phone number","sensitive":false,"sourceQuote":"provide a way of contacting you (such as an email address and/or phone number)"},{"name":"birthday","sensitive":false,"sourceQuote":"You''ll also need to provide your birthday"},{"name":"IP address","sensitive":false,"sourceQuote":"this includes information like your IP address, operating system information, browser information"},{"name":"device information","sensitive":false,"sourceQuote":"We collect information about the device you are using to access the services"},{"name":"messages","sensitive":true,"sourceQuote":"you may write messages or posts (including drafts), send voice messages"},{"name":"voice messages","sensitive":true,"sourceQuote":"you may write messages or posts (including drafts), send voice messages"},{"name":"payment information","sensitive":true,"sourceQuote":"you may need to submit a valid payment method and associated billing information, including your full name and billing address"},{"name":"game activity","sensitive":false,"sourceQuote":"We may also collect limited information from your device while Discord is running (such as the game you are playing)"},{"name":"location data","sensitive":true,"sourceQuote":"Policy does not explicitly mention collection of precise location data; assuming collection based on IP address tracking"}],"collectsPreciseGeolocation":{"value":false,"confidence":0.7,"sourceQuote":"The policy mentions IP address collection but does not explicitly state collection of GPS or precise location data"},"collectsBiometricData":{"value":false,"confidence":0.9,"sourceQuote":"No mention of fingerprint, face recognition, voiceprint, or retina scan collection in the policy"},"collectsHealthData":{"value":false,"confidence":0.9,"sourceQuote":"No mention of health, medical, fitness, or wellness data collection in the policy"},"collectsFinancialData":{"value":true,"confidence":0.95,"sourceQuote":"you may need to submit a valid payment method and associated billing information, including your full name and billing address"}},"dataSharing":{"soldToThirdParties":{"value":false,"confidence":0.97,"sourceQuote":"We don''t sell your personal information. Our business is funded through subscriptions, paid products, and sponsored content, not based on selling your personal information to third parties."},"sharedForAdvertising":{"value":true,"confidence":0.85,"sourceQuote":"We may provide limited information to advertising platforms to help us reach people that we think will like our products and to measure the performance of our ads shown on those platforms"},"crossSiteTracking":{"value":true,"confidence":0.8,"sourceQuote":"When you take certain actions on other sites, we may receive information about you. For example, when we advertise for Discord on third party platforms, if you click on the ad, we may receive information about which ad you saw and on which platform"},"usedForProfiling":{"value":true,"confidence":0.9,"sourceQuote":"We use your information to personalize our services. This can include customizing your experience on Discord so that you see communities, activities, applications, features or promotions from us, or other content that may be of interest to you"},"usedToTrainAI":{"value":true,"confidence":0.85,"sourceQuote":"We use certain information, which may include content reported to us, content that violates our Terms of Service, and certain other content widely available on the service... to create systems and models that can be automated to more swiftly detect, categorize, and take action against prohibited content or conduct"},"thirdPartyCount":6},"retention":{"retentionDays":null,"indefinite":true,"sourceQuote":"We retain personal information until we determine it is no longer needed for the processing purposes for which we collected or retain it or for legal compliance"},"consumerRights":{"rightToAccess":{"value":true,"confidence":0.95,"sourceQuote":"If you want to see what information we have collected about you, you can request a copy of your data in the Data & Privacy section of your User Settings"},"rightToDelete":{"value":true,"confidence":0.95,"sourceQuote":"You can disable or delete your account via the User Settings menu... Deleting your account permanently deletes identifying information and anonymizes other data"},"rightToPortability":{"value":true,"confidence":0.9,"sourceQuote":"Data is delivered in common digital formats, including JSON and any other file format you used when uploading attachments to the services"},"rightToCorrect":{"value":true,"confidence":0.9,"sourceQuote":"You may edit or delete specific pieces of information within the services: You can edit or delete any message you have sent or content you have posted"},"rightToOptOut":{"value":true,"confidence":0.85,"sourceQuote":"Limit our ability to use your data to improve our services... Limit our ability to personalize Discord for you"},"rightToNonDiscrimination":{"value":false,"confidence":0.4,"sourceQuote":"Policy does not explicitly mention right to non-discrimination; assuming not provided"}},"signalHonoring":{"honorsGPC":{"value":false,"confidence":0.4,"sourceQuote":"Policy does not mention Global Privacy Control (GPC). Defaulting to not honored."},"honorsDNT":{"value":false,"confidence":0.4,"sourceQuote":"Policy does not mention Do Not Track (DNT). Defaulting to not honored."}},"security":{"measures":[{"name":"encryption in transit","sourceQuote":"All information sent within our services is encrypted both in transit and at rest"},{"name":"encryption at rest","sourceQuote":"All information sent within our services is encrypted both in transit and at rest"},{"name":"TLS encryption","sourceQuote":"we use Transport Layer Security (\"TLS\") to encrypt text and images in transit"},{"name":"access controls","sourceQuote":"We also enforce technical and administrative access controls to limit which of our employees and contractors have access to nonpublic personal information"},{"name":"end-to-end encryption","sourceQuote":"Voice and video communications on Discord are designed to be end-to-end encrypted"},{"name":"two-factor authentication","sourceQuote":"You can help maintain the security of your account by configuring two-factor authentication"}]}}', 59, 'C', 'Fair', '#b45309', '1', '[{"key":"soldToThirdParties","label":"Data sold to third parties","points":0,"triggered":false},{"key":"sharedForAdvertising","label":"Data shared for advertising","points":-10,"triggered":true},{"key":"crossSiteTracking","label":"Cross-site tracking","points":-10,"triggered":true},{"key":"usedForProfiling","label":"Used for profiling / AI decisions","points":-8,"triggered":true},{"key":"usedToTrainAI","label":"Used to train AI models","points":-8,"triggered":true},{"key":"collectsPreciseGeolocation","label":"Collects precise geolocation","points":0,"triggered":false},{"key":"collectsBiometricData","label":"Collects biometric data","points":0,"triggered":false},{"key":"collectsHealthData","label":"Collects health data","points":0,"triggered":false},{"key":"collectsFinancialData","label":"Collects financial data","points":-3,"triggered":true},{"key":"doesNotHonorGPC","label":"Does not honor GPC","points":-5,"triggered":true},{"key":"doesNotHonorDNT","label":"Does not honor DNT","points":-2,"triggered":true},{"key":"thirdPartiesOver10","label":"More than 10 third parties","points":0,"triggered":false,"detail":"6 third parties disclosed"},{"key":"thirdParties6To10","label":"6–10 third parties","points":-5,"triggered":true,"detail":"6 third parties disclosed"},{"key":"retentionIndefinite","label":"Retention is indefinite","points":-10,"triggered":true},{"key":"retentionOver3Years","label":"Retention longer than 3 years","points":0,"triggered":false},{"key":"retentionOver1Year","label":"Retention longer than 1 year","points":0,"triggered":false},{"key":"consumerRights","label":"Consumer rights available","points":10,"triggered":true,"detail":"5 of 6 rights offered"},{"key":"securityMeasures","label":"Security measures in place","points":10,"triggered":true,"detail":"5 of 5 measures"}]', 'claude-sonnet-4-20250514', 10050, 1983, 34318, 0, '2026-03-21T06:17:47Z');
INSERT OR IGNORE INTO extractions (id, policy_id, company_id, facts_json, score, letter, grade_label, grade_color, rubric_version, breakdown_json, model, input_tokens, output_tokens, latency_ms, chunked, created_at) VALUES (10, 10, 10, '{"metadata":{"schemaVersion":"1.0.0","companyName":"Reddit Inc.","policyUrl":"https://www.reddit.com/policies/privacy-policy","analyzedAt":"2026-03-21T06:17:50.991Z","policyHash":"1cf1490229804738f20ce4d9a5b181184a3b4ed886c82a56d7512fe71123f0b2","policyEffectiveDate":"January 6, 2026"},"dataCollection":{"items":[{"name":"Username","sensitive":false,"sourceQuote":"If you create a Reddit account, your account will have a username, which you provide or which is automatically generated."},{"name":"Password","sensitive":true,"sourceQuote":"You may need to provide a password, depending on whether you register using an email address, Single Sign-On (SSO) feature (such as Apple or Google), or phone number."},{"name":"Email address","sensitive":false,"sourceQuote":"You may need to provide a password, depending on whether you register using an email address, Single Sign-On (SSO) feature"},{"name":"Phone number","sensitive":false,"sourceQuote":"You may need to provide a password, depending on whether you register using an email address, Single Sign-On (SSO) feature (such as Apple or Google), or phone number."},{"name":"Birthday","sensitive":false,"sourceQuote":"When you use Reddit, you may also provide other information, such as a bio, gender, birthday, location, language, profile picture, or social link."},{"name":"Location","sensitive":false,"sourceQuote":"When you use Reddit, you may also provide other information, such as a bio, gender, birthday, location, language, profile picture, or social link."},{"name":"IP address","sensitive":false,"sourceQuote":"This may include your IP address, user-agent string, browser type, operating system, referral URLs, device information (such as device IDs), device settings, and mobile carrier name."},{"name":"Device information","sensitive":false,"sourceQuote":"This may include your IP address, user-agent string, browser type, operating system, referral URLs, device information (such as device IDs), device settings, and mobile carrier name."},{"name":"Payment information","sensitive":true,"sourceQuote":"If you purchase products or services from us or otherwise through the Services, you will have to provide payment information in order to complete your purchase."},{"name":"Government ID","sensitive":true,"sourceQuote":"If you sign up to participate in a Reddit Program (for example, our Contributor Program), we collect, directly or indirectly through our providers, some additional information from you (such as your name, date of birth, address, email, tax, government ID, and payment information)."},{"name":"Posts and comments","sensitive":false,"sourceQuote":"Public content you submit includes your public posts, comments, and chat messages, usernames, and some of your profile information"},{"name":"Private messages","sensitive":true,"sourceQuote":"Non-public content you submit includes your saved drafts of posts or comments, your non-public messages with other users (such as private messages, private chats, and modmail)"},{"name":"Usage patterns","sensitive":false,"sourceQuote":"We collect information about how you use our Services, like pages visited, how you interact with content, ads, and communities, upvotes/downvotes, links clicked, the requested URL, and search terms."},{"name":"Blockchain addresses","sensitive":false,"sourceQuote":"We may also collect public blockchain data and addresses, such as when you purchase or create a Collectible Avatar, receive or mint an NFT, or create a Reddit Vault."}],"collectsPreciseGeolocation":{"value":false,"confidence":0.85,"sourceQuote":"We automatically collect information about your approximate location based on our Logs Data. We don''t track your precise location."},"collectsBiometricData":{"value":false,"confidence":0.9,"sourceQuote":"Policy does not mention collection of biometric data such as fingerprints, face recognition, or voiceprints."},"collectsHealthData":{"value":false,"confidence":0.9,"sourceQuote":"Policy does not mention collection of health, medical, or wellness data."},"collectsFinancialData":{"value":true,"confidence":0.95,"sourceQuote":"If you purchase products or services from us or otherwise through the Services, you will have to provide payment information in order to complete your purchase."}},"dataSharing":{"soldToThirdParties":{"value":false,"confidence":0.95,"sourceQuote":"We don''t sell your personal data to third parties, including data brokers."},"sharedForAdvertising":{"value":true,"confidence":0.9,"sourceQuote":"third-party ad serving and measurement providers who help us and advertisers serve relevant ads and measure the performance of ads"},"crossSiteTracking":{"value":true,"confidence":0.85,"sourceQuote":"we may receive limited information about your activity on the advertiser''s site or app, such as whether you bought something from the advertiser"},"usedForProfiling":{"value":true,"confidence":0.9,"sourceQuote":"We infer attributes such as age range, gender, and/or preferred language(s) based on the information we have about you."},"usedToTrainAI":{"value":false,"confidence":0.6,"sourceQuote":"Policy mentions ''research and develop new services'' but does not explicitly state data is used to train AI models."},"thirdPartyCount":null},"retention":{"retentionDays":null,"indefinite":true,"sourceQuote":"We store the information we collect for as long as it is necessary for the purpose(s) for which we originally collected it. We may retain certain information for legitimate business purposes and/or if we believe doing so is in accordance with, or as required by, any applicable law."},"consumerRights":{"rightToAccess":{"value":true,"confidence":0.95,"sourceQuote":"You can also request a copy of the personal information Reddit maintains about you by following the process described here."},"rightToDelete":{"value":true,"confidence":0.95,"sourceQuote":"You may delete your account at any time from the settings page in your account."},"rightToPortability":{"value":true,"confidence":0.85,"sourceQuote":"Users in the EEA, Switzerland, and UK have the right to request access to, rectification of, or erasure of their personal data; to data portability in certain circumstances"},"rightToCorrect":{"value":true,"confidence":0.9,"sourceQuote":"You can access your information and change or correct certain information through the Services."},"rightToOptOut":{"value":true,"confidence":0.9,"sourceQuote":"You may opt out of us using information we collect from third parties, including advertising partners, to personalize the ads you see on and off Reddit."},"rightToNonDiscrimination":{"value":true,"confidence":0.9,"sourceQuote":"Reddit does not discriminate against users for exercising their rights under data protection laws."}},"signalHonoring":{"honorsGPC":{"value":true,"confidence":0.9,"sourceQuote":"If you have an account with us and you visit our site with an opt-out preference signal (such as Global Privacy Control) enabled, we will treat that as an opt-out request."},"honorsDNT":{"value":false,"confidence":0.95,"sourceQuote":"Most modern web browsers give you the option to send a Do Not Track signal to the sites you visit, indicating that you do not wish to be tracked. However, there is no accepted standard for how a site should respond to this signal, and we do not take any action in response to this signal."}},"security":{"measures":[{"name":"HTTPS encryption","sourceQuote":"For example, we use HTTPS while information is being transmitted."},{"name":"Access controls","sourceQuote":"We also enforce technical and administrative access controls to limit which of our employees have access to non-public personal information."},{"name":"Two-factor authentication","sourceQuote":"You can help maintain the security of your account by configuring two-factor authentication."}]}}', 75, 'B', 'Good', '#4d7c0f', '1', '[{"key":"soldToThirdParties","label":"Data sold to third parties","points":0,"triggered":false},{"key":"sharedForAdvertising","label":"Data shared for advertising","points":-10,"triggered":true},{"key":"crossSiteTracking","label":"Cross-site tracking","points":-10,"triggered":true},{"key":"usedForProfiling","label":"Used for profiling / AI decisions","points":-8,"triggered":true},{"key":"usedToTrainAI","label":"Used to train AI models","points":0,"triggered":false},{"key":"collectsPreciseGeolocation","label":"Collects precise geolocation","points":0,"triggered":false},{"key":"collectsBiometricData","label":"Collects biometric data","points":0,"triggered":false},{"key":"collectsHealthData","label":"Collects health data","points":0,"triggered":false},{"key":"collectsFinancialData","label":"Collects financial data","points":-3,"triggered":true},{"key":"doesNotHonorGPC","label":"Does not honor GPC","points":0,"triggered":false},{"key":"doesNotHonorDNT","label":"Does not honor DNT","points":-2,"triggered":true},{"key":"thirdPartiesOver10","label":"More than 10 third parties","points":0,"triggered":false},{"key":"thirdParties6To10","label":"6–10 third parties","points":0,"triggered":false},{"key":"retentionIndefinite","label":"Retention is indefinite","points":-10,"triggered":true},{"key":"retentionOver3Years","label":"Retention longer than 3 years","points":0,"triggered":false},{"key":"retentionOver1Year","label":"Retention longer than 1 year","points":0,"triggered":false},{"key":"consumerRights","label":"Consumer rights available","points":12,"triggered":true,"detail":"6 of 6 rights offered"},{"key":"securityMeasures","label":"Security measures in place","points":6,"triggered":true,"detail":"3 of 5 measures"}]', 'claude-sonnet-4-20250514', 10563, 2199, 37316, 0, '2026-03-21T06:18:28Z');
INSERT OR IGNORE INTO extractions (id, policy_id, company_id, facts_json, score, letter, grade_label, grade_color, rubric_version, breakdown_json, model, input_tokens, output_tokens, latency_ms, chunked, created_at) VALUES (11, 11, 11, '{"metadata":{"schemaVersion":"1.0.0","companyName":"Pinterest","policyUrl":"https://policy.pinterest.com/en/privacy-policy","analyzedAt":"2026-03-21T06:17:50.999Z","policyHash":"4bd603901fa965fa8fd2c8990a39b421133005829d439d950ffc9eecb771c416","policyEffectiveDate":"April 30, 2025"},"dataCollection":{"items":[{"name":"Account Information","sensitive":false,"sourceQuote":"When you join our Services, we collect information like your name, email address, birthday, gender, country of residence, your interests, and preferred language."},{"name":"Content","sensitive":false,"sourceQuote":"We collect information when you save or upload Pins, photos, or other content, interact with Pins or other content (for example, commenting or adding a Pin), or where you send messages and interact with other users."},{"name":"Precise location information","sensitive":true,"sourceQuote":"Depending on where you live, you can choose to share your precise location using your device settings."},{"name":"Communications with Pinterest","sensitive":false,"sourceQuote":"If you contact us for customer support or otherwise communicate with us, we collect the content of these communications."},{"name":"Contacts","sensitive":true,"sourceQuote":"If you previously chose to sync your contacts with your account, we will continue to process certain information about your contacts who are Pinterest users to help you find one another on our Services."},{"name":"Device information","sensitive":false,"sourceQuote":"We collect information about the device you use to access our Services, including the type of device, operating system, network service provider, settings, and unique device identifiers."},{"name":"Log data","sensitive":false,"sourceQuote":"When you use our Services, our servers record information (''log data''), including information that your browser automatically sends whenever you visit a website, or that your mobile app automatically sends when you''re using it."},{"name":"Cookie and similar technology data","sensitive":false,"sourceQuote":"We also use ''cookies'' or similar technologies to obtain log data."},{"name":"Usage data and inferences","sensitive":false,"sourceQuote":"When you''re on our Services, we use your activity—such as which Pins you click on, terms you search for, boards you create, and any text that you add in a comment or description—along with other information you''ve provided when you first signed up and information from our partners and advertisers to make inferences about you and your preferences."},{"name":"IP address location","sensitive":false,"sourceQuote":"We use your IP address to infer your approximate location, even if you don''t choose to share your precise location, and photos you share may include information about the location where they were taken."},{"name":"Third party platform data","sensitive":false,"sourceQuote":"If you register for or log into the Service using a third party platform (like Facebook or Google), they will furnish certain information to us to facilitate your account creation or log-in with us."},{"name":"Advertiser and partner data","sensitive":false,"sourceQuote":"Online advertisers or third parties provide information to us about you to measure, report on or improve the performance of ads on Pinterest, or to help us better understand what kinds of ads to show you on Pinterest."},{"name":"Race and ethnicity","sensitive":true,"sourceQuote":"If you have a business account, depending on where you live, you may also have the option to add race and ethnicity information to your profile."}],"collectsPreciseGeolocation":{"value":true,"confidence":0.95,"sourceQuote":"Depending on where you live, you can choose to share your precise location using your device settings."},"collectsBiometricData":{"value":true,"confidence":0.85,"sourceQuote":"Conduct age verification, as appropriate. This may include facial age estimation and matching your face against a government ID."},"collectsHealthData":{"value":false,"confidence":0.7,"sourceQuote":"Policy does not explicitly mention collection of health or medical data."},"collectsFinancialData":{"value":false,"confidence":0.6,"sourceQuote":"Policy does not explicitly mention collection of financial data such as bank accounts or credit cards."}},"dataSharing":{"soldToThirdParties":{"value":false,"confidence":0.4,"sourceQuote":"Some of these activities may be considered ''targeted advertising'' ''sharing'' or ''selling'' as those terms are defined under certain state privacy laws in the US. You can opt out of Pinterest using and disclosing your information for these purposes."},"sharedForAdvertising":{"value":true,"confidence":0.95,"sourceQuote":"we share data for advertising and related purposes, including showing you ads about Pinterest on third-party services, enabling partners to show you ads both on and off Pinterest, and helping advertisers understand how ads on Pinterest perform."},"crossSiteTracking":{"value":true,"confidence":0.9,"sourceQuote":"we may receive information about your visits to an advertiser''s site, or purchases you made from them, or information about your interests from a third-party service, which we might use to help show you ads on the Service. Sometimes we get this information through the Pinterest Tag (a piece of code an advertiser puts on their site)"},"usedForProfiling":{"value":true,"confidence":0.9,"sourceQuote":"we use your activity—such as which Pins you click on, terms you search for, boards you create, and any text that you add in a comment or description—along with other information you''ve provided when you first signed up and information from our partners and advertisers to make inferences about you and your preferences."},"usedToTrainAI":{"value":true,"confidence":0.95,"sourceQuote":"using information to train, develop and improve our technology such as our machine learning models, regardless of when Pins were posted. This includes, for example, Pinterest''s body type technology, which is trained on images in Pins posted to our Services. Pinterest also has features that are supported by generative artificial intelligence technology."},"thirdPartyCount":null},"retention":{"retentionDays":750,"indefinite":false,"sourceQuote":"We generally keep log data for a period of 25 months to provide our Services to you, to make Pinterest safe, improve our product features, and to deliver ads that are relevant, interesting and personal to you."},"consumerRights":{"rightToAccess":{"value":true,"confidence":0.95,"sourceQuote":"Access: You can request access to the information we collect and hold about you in a portable format."},"rightToDelete":{"value":true,"confidence":0.95,"sourceQuote":"Deletion/erasure: You can have your information deleted. In your settings, select ''Delete your data and account'' and follow the instructions."},"rightToPortability":{"value":true,"confidence":0.9,"sourceQuote":"Right to portability: You can have the information you provided to us sent to another organization, where we hold this information with your consent or for the performance of a contract with you, and, where it''s technically feasible for us to do so."},"rightToCorrect":{"value":true,"confidence":0.95,"sourceQuote":"Correction/rectification: You can correct your information by updating information in your profile."},"rightToOptOut":{"value":true,"confidence":0.95,"sourceQuote":"Opt out of ''targeted advertising'' ''sharing'' or ''sale'': As explained above some of our activities may constitute ''targeted advertising,'' ''sharing,'' or ''selling'' as those terms are defined under certain state privacy laws in the U.S. You may opt out at any time by following the instructions in your Privacy and Data Settings menu."},"rightToNonDiscriminati