INSERT OR IGNORE INTO extractions (id, policy_id, company_id, facts_json, score, letter, grade_label, grade_color, rubric_version, breakdown_json, model, input_tokens, output_tokens, latency_ms, chunked, created_at) VALUES (19, 19, 19, '{"metadata":{"schemaVersion":"1.0.0","companyName":"Stripe Inc.","policyUrl":"https://stripe.com/privacy","analyzedAt":"2026-03-21T06:30:36.556Z","policyHash":"687aeec75a819b006da31b9aba8244efbf579e23ce34042b6c003e1d65ade3d1","policyEffectiveDate":"February 23, 2026"},"dataCollection":{"items":[{"name":"Transaction Data","sensitive":true,"sourceQuote":"Transaction Data refers to data collected or used by Stripe in relation to transactions you request. Some Transaction Data is Personal Data and may include: your name, email address, contact number, billing and shipping address, payment method information (like credit or debit card number, bank or payment method account details, or payment card image chosen by you)"},{"name":"Bank account information","sensitive":true,"sourceQuote":"You can also share and save bank account details to your Link account using Stripe''s Financial Connections product. When you use Financial Connections, Stripe will periodically collect and process your account information (such as bank account owner information, account balances, account number and details, account transactions, and, in some cases, log-in credentials)"},{"name":"Identity documents","sensitive":true,"sourceQuote":"Finally, you can use Link to store your identity documents (such as your driver''s license) and other identification information (such as tax ID) so that you can share them in future interactions with Stripe or its Business Users"},{"name":"Biometric data","sensitive":true,"sourceQuote":"You can separately consent to us using your biometric data to enhance our verification technology, with the option to revoke your consent at any time"},{"name":"Credit reports","sensitive":true,"sourceQuote":"We may also obtain credit reports about you from credit bureaus to determine your eligibility"},{"name":"Device and browser information","sensitive":false,"sourceQuote":"The devices and browsers you use across our Sites and third-party websites, apps, and other online services"},{"name":"IP address","sensitive":false,"sourceQuote":"usage data associated with those devices and browsers and your engagement with our Services, including data elements like IP address"},{"name":"Location data","sensitive":false,"sourceQuote":"We may also associate a location with your visit"}],"collectsPreciseGeolocation":{"value":false,"confidence":0.7,"sourceQuote":"We may also associate a location with your visit"},"collectsBiometricData":{"value":true,"confidence":0.95,"sourceQuote":"You can separately consent to us using your biometric data to enhance our verification technology, with the option to revoke your consent at any time"},"collectsHealthData":{"value":false,"confidence":0.9,"sourceQuote":"No mention of health or medical data collection found in the policy"},"collectsFinancialData":{"value":true,"confidence":0.98,"sourceQuote":"Transaction Data includes payment method information (like credit or debit card number, bank or payment method account details, or payment card image chosen by you)"}},"dataSharing":{"soldToThirdParties":{"value":true,"confidence":0.8,"sourceQuote":"We do not transfer your Personal Data to third parties in exchange for payment. However, as noted above, we may provide the data to third party partners, such as advertising partners, analytics providers, and social networks, who assist us in advertising our products and Services to you. Because these third parties may use the data Stripe provides for their own purposes, Stripe''s provision of data to these parties may be considered a data ''sale'' or ''sharing'' (for behavioral advertising) as those terms are defined under the CCPA and other applicable US privacy laws"},"sharedForAdvertising":{"value":true,"confidence":0.95,"sourceQuote":"Subject to applicable law, including any consent requirements, we use and share End User Personal Data with third party partners to allow us to advertise our End User Services to you, including through interest-based advertising, and to track the efficacy of such ads"},"crossSiteTracking":{"value":true,"confidence":0.85,"sourceQuote":"Stripe may use cookies and similar technologies or the data you provide to our Business Users (such as when you input your email address on a Business User''s website) to recognize you and help you use Link when visiting our Business User''s website"},"usedForProfiling":{"value":true,"confidence":0.9,"sourceQuote":"Analyzing and drawing inferences from Transaction Data to reduce costs, fraud, and disputes and increase authentication and authorization rates for Stripe and our Business Users"},"usedToTrainAI":{"value":true,"confidence":0.92,"sourceQuote":"Training artificial intelligence models to power our Services and protect against fraud and other harm"},"thirdPartyCount":null},"retention":{"retentionDays":null,"indefinite":true,"sourceQuote":"We retain your Personal Data for as long as we continue to provide the Services to you or our Business Users, or for a period in which we reasonably foresee continuing to provide the Services. Even after we stop providing Services directly to you or to a Business User that you''re doing business with, and even after you close your Stripe account or complete a transaction with a Business User, we may continue to retain your Personal Data"},"consumerRights":{"rightToAccess":{"value":true,"confidence":0.95,"sourceQuote":"The right to request access to the Personal Data Stripe processes about you"},"rightToDelete":{"value":true,"confidence":0.95,"sourceQuote":"The right to request that Stripe erase your Personal Data in certain circumstances as provided by law"},"rightToPortability":{"value":true,"confidence":0.9,"sourceQuote":"The right to request that we export the Personal Data we hold about you to another company, provided it''s technically feasible"},"rightToCorrect":{"value":true,"confidence":0.95,"sourceQuote":"The right to request that Stripe rectify or update your Personal Data if it''s inaccurate, incomplete, or outdated"},"rightToOptOut":{"value":true,"confidence":0.9,"sourceQuote":"You can opt out of targeted advertising and any related data ''sales'' or ''sharing'' (for behavioral advertising)"},"rightToNonDiscrimination":{"value":true,"confidence":0.9,"sourceQuote":"The right not to be discriminated against for exercising these rights"}},"signalHonoring":{"honorsGPC":{"value":true,"confidence":0.98,"sourceQuote":"Stripe honors the Global Privacy Control (GPC) opt-out preference signals"},"honorsDNT":{"value":false,"confidence":0.8,"sourceQuote":"Policy mentions GPC but does not mention Do Not Track (DNT) signals"}},"security":{"measures":[{"name":"Technical safeguards","sourceQuote":"We maintain organizational, technical, and administrative measures designed to protect the Personal Data covered by this Policy from unauthorized access, destruction, loss, alteration, or misuse"},{"name":"Computer safeguards","sourceQuote":"To protect your personal information from unauthorized access, destruction, loss, alteration, or misuse we use security measures to comply with federal law. These measures include computer safeguards and secured files and buildings"},{"name":"Access controls","sourceQuote":"We impose access controls along with ongoing monitoring to prevent data misuse"},{"name":"Strong passwords","sourceQuote":"If you hold a Stripe account, you can do so by using a strong password, safeguarding your password or API key against unauthorized use"}]}}', 36, 'F', 'Failing', '#b91c1c', '1', '[{"key":"soldToThirdParties","label":"Data sold to third parties","points":-25,"triggered":true},{"key":"sharedForAdvertising","label":"Data shared for advertising","points":-10,"triggered":true},{"key":"crossSiteTracking","label":"Cross-site tracking","points":-10,