ring'' link in your Privacy Controls in the app or broadcast an Opt-Out Preference Signal, such as the Global Privacy Control."},"honorsDNT":{"value":false,"confidence":0.95,"sourceQuote":"Note that Do Not Track (DNT) is a privacy preference you can set in browsers, but we do not currently process DNT signals."}},"security":{"measures":[{"name":"administrative safeguards","sourceQuote":"We maintain administrative, technical, and physical safeguards in accordance with appropriate industry standards that are designed to protect against unauthorized use, disclosure, or access to personal information."},{"name":"technical safeguards","sourceQuote":"We maintain administrative, technical, and physical safeguards in accordance with appropriate industry standards that are designed to protect against unauthorized use, disclosure, or access to personal information."},{"name":"physical safeguards","sourceQuote":"We maintain administrative, technical, and physical safeguards in accordance with appropriate industry standards that are designed to protect against unauthorized use, disclosure, or access to personal information."},{"name":"PCI compliant payment processing","sourceQuote":"Instead, we use Payment Card Industry compliant third-party payment services."}]}}', 56, 'C', 'Fair', '#b45309', '1', '[{"key":"soldToThirdParties","label":"Data sold to third parties","points":0,"triggered":false},{"key":"sharedForAdvertising","label":"Data shared for advertising","points":-10,"triggered":true},{"key":"crossSiteTracking","label":"Cross-site tracking","points":-10,"triggered":true},{"key":"usedForProfiling","label":"Used for profiling / AI decisions","points":-8,"triggered":true},{"key":"usedToTrainAI","label":"Used to train AI models","points":-8,"triggered":true},{"key":"collectsPreciseGeolocation","label":"Collects precise geolocation","points":-8,"triggered":true},{"key":"collectsBiometricData","label":"Collects biometric data","points":0,"triggered":false},{"key":"collectsHealt