INSERT OR IGNORE INTO extractions (id, policy_id, company_id, facts_json, score, letter, grade_label, grade_color, rubric_version, breakdown_json, model, input_tokens, output_tokens, latency_ms, chunked, created_at) VALUES (39, 39, 39, '{"metadata":{"schemaVersion":"1.0.0","companyName":"Tinder (Match Group)","policyUrl":"https://policies.tinder.com/privacy/intl/en/","analyzedAt":"2026-03-21T06:49:07.529Z","policyHash":"b321f2953ed6961a6878ff2977e66b887c12d3690dc97ceb63ad43f984ad0c27","policyEffectiveDate":"April 4, 2026"},"dataCollection":{"items":[{"name":"Account data","sensitive":false,"sourceQuote":"When you create an account, you give us basic information for your account to be set up such as your phone number, email address, and date of birth."},{"name":"Profile data","sensitive":true,"sourceQuote":"When you complete your profile, you share additional details about you, such as your gender, interests, preferences, approximate location, etc. Some of this data may be considered sensitive or special in certain countries, such as details about sexual orientation, sexual life, health, or political beliefs."},{"name":"Content","sensitive":true,"sourceQuote":"When you use our service, you share photos, videos, audio, text and other types of content, such as your search queries or chats with other members."},{"name":"Purchase data","sensitive":true,"sourceQuote":"When you make a purchase or request a refund, we keep the details of the transaction (e.g., what you purchased, the date of the transaction, and the price). The exact data depends on the payment method you choose. When you pay directly with us (rather than through a platform such as iOS or Android), you provide your debit or credit card number or other financial info."},{"name":"Usage data","sensitive":false,"sourceQuote":"Using the service generates data about your activity, including how you use it (e.g., when you logged in, features you''ve been using, actions taken, information shown to you, referring webpages, ads you interacted with) and how you interact with others (e.g., searching, matching, communicating)."},{"name":"Technical data","sensitive":false,"sourceQuote":"Using the service involves the collection of data from and about the device(s) you use to access our service, including hardware and software information such as IP address, device ID device type, operating systems and configurations, network information, device movement and sensor data, as well as app settings and characteristics, app crashes, advertising IDs and identifiers associated with cookies or other technologies that can uniquely identify a device or browser."},{"name":"Geolocation data","sensitive":true,"sourceQuote":"If you give us permission, we can collect your geolocation (latitude and longitude) from your device."},{"name":"Face data","sensitive":true,"sourceQuote":"You may choose to participate in certain of our features like Photo Verification, Photo Check, or ID + Photo Verification, that involve the collection of face geometry data, which may be considered biometric data in some jurisdictions."},{"name":"ID data","sensitive":true,"sourceQuote":"You may provide us with a copy of your government-issued ID to help us check that you''re who you say you are."}],"collectsPreciseGeolocation":{"value":true,"confidence":0.95,"sourceQuote":"If you give us permission, we can collect your geolocation (latitude and longitude) from your device."},"collectsBiometricData":{"value":true,"confidence":0.95,"sourceQuote":"You may choose to participate in certain of our features like Photo Verification, Photo Check, or ID + Photo Verification, that involve the collection of face geometry data, which may be considered biometric data in some jurisdictions."},"collectsHealthData":{"value":true,"confidence":0.85,"sourceQuote":"Some of this data may be considered sensitive or special in certain countries, such as details about sexual orientation, sexual life, health, or political beliefs."},"collectsFinancialData":{"value":true,"confidence":0.95,"sourceQuote":"When you pay directly with us (rather than through a platform such as iOS or Android), you provide your debit or credit card number or other financial info."}},"dataSharing":{"soldToThirdParties":{"value":true,"confidence":0.85,"sourceQuote":"If we ''sell'' or ''share'' your data or use it for ''targeted advertising,'' we will provide an opt out in the ''Your Privacy Choices'' link in the footer of our website and in the Settings menu of the app."},"sharedForAdvertising":{"value":true,"confidence":0.95,"sourceQuote":"We publish ads about third-party advertisers'' products and services on our service, and publish ads promoting our own service on third-party sites and apps. To help improve the relevance of these ads, we provide certain info about you to third parties, including advertising partners, or allow them to collect such data from our services."},"crossSiteTracking":{"value":true,"confidence":0.9,"sourceQuote":"We also receive data related to interactions you had with our ads on third party websites or apps, if applicable."},"usedForProfiling":{"value":true,"confidence":0.95,"sourceQuote":"Using the service involves the generation of insights and inferences, drawn from your interactions and the information and content you provide, reflecting, e.g., your preferences, characteristics, predispositions, behavior, and attitudes."},"usedToTrainAI":{"value":true,"confidence":0.85,"sourceQuote":"Developing and improving new features and services, including through machine learning and other technologies"},"thirdPartyCount":null},"retention":{"retentionDays":null,"indefinite":false,"sourceQuote":"We keep your personal data only as long as necessary for legitimate business reasons (as laid out in Section 4) and as permitted by applicable law. Following account closure, we delete your data as laid out below: To protect the safety and security of our members, we implement a safety retention window of three months following account closure or one year following an account ban."},"consumerRights":{"rightToAccess":{"value":true,"confidence":0.95,"sourceQuote":"You can access and review some data directly by logging into your account. You can also retrieve a copy of your data by following the process explained here."},"rightToDelete":{"value":true,"confidence":0.95,"sourceQuote":"You can delete some of the data you provided us directly within the service. You can also close your account as explained here and we''ll delete your data as laid out in this Privacy Policy."},"rightToPortability":{"value":true,"confidence":0.95,"sourceQuote":"You can also retrieve a copy of your data by following the process explained here."},"rightToCorrect":{"value":true,"confidence":0.95,"sourceQuote":"You can update your data directly within the service by simply updating your profile. If you wish to rectify other data, please contact us here."},"rightToOptOut":{"value":true,"confidence":0.95,"sourceQuote":"If you live in the United States, you may opt out of activities that may fall under the legal definitions of ''targeted advertising,'' ''sales,'' or ''sharing'' under applicable laws, if we use your data for such purposes."},"rightToNonDiscrimination":{"value":false,"confidence":0.4,"sourceQuote":"Policy does not explicitly mention right to non-discrimination. Defaulting to false with low confidence."}},"signalHonoring":{"honorsGPC":{"value":false,"confidence":0.4,"sourceQuote":"Policy does not mention Global Privacy Control (GPC). Defaulting to not honored."},"honorsDNT":{"value":false,"confidence":0.4,"sourceQuote":"Policy does not mention Do Not Track (DNT). Defaulting to not honored."}},"security":{"measures":[{"name":"Data security operations","sourceQuote":"They provide us services such as data hosting and maintenance, analytics, customer care, marketing, advertising, payment and refund processing, legal support, and security operations."},{"name":"Safety and security systems","sourceQuote":"We also process your data to keep our service, you, and others safe and secure. We take this responsibility very seriously and we''re always working to improve the safety and security of our systems and processes."},{"name":"Cross-border transfer safeguards","sourceQuote":"When we transfer personal data to a third country, we use appropriate mechanisms. For example, we rely on: Adequacy decisions issued by the European Commission or other competent authorities under applicable laws... Standard contractual clauses issued by the European Commission or similar contractual data transfer mechanisms approved by other competent authorities under applicable laws."}]}}', 24, 'F', 'Failing', '#b91c1c', '1', '[{"key":"soldToThirdParties","label":"Data sold to third parties","points":-25,"triggered":true},{"key":"sharedForAdvertising","label":"Data shared for advertising","points":-10,"triggered":true},{"key":"crossSiteTracking","label":"Cross-site tracking","points":-10,"triggered":true},{"key":"usedForProfiling","label":"Used for profiling / AI decisions","points":-8,"triggered":true},{"key":"usedToTrainAI","label":"Used to train AI models","points":-8,"triggered":true},{"key":"collectsPreciseGeolocation","label":"Collects precise geolocation","points":-8,"triggered":true},{"key":"collectsBiometricData","label":"Collects biometric data","points":-8,"triggered":true},{"key":"collectsHealthData","label":"Collects health data","points":-5,"triggered":true},{"key":"collectsFinancialData","label":"Collects financial data","points":-3,"triggered":true},{"key":"doesNotHonorGPC","label":"Does not honor GPC","points":-5,"triggered":true},{"key":"doesNotHonorDNT","label":"Does not honor DNT","points":-2,"triggered":true},{"key":"thirdPartiesOver10","label":"More than 10 third parties","points":0,"triggered":false},{"key":"thirdParties6To10","label":"6–10 third parties","points":0,"triggered":false},{"key":"retentionIndefinite","label":"Retention is indefinite","points":0,"triggered":false},{"key":"retentionOver3Years","label":"Retention longer than 3 years","points":0,"triggered":false},{"key":"retentionOver1Year","label":"Retention longer than 1 year","points":0,"triggered":false},{"key":"consumerRights","label":"Consumer rights available","points":10,"triggered":true,"detail":"5 of 6 rights offered"},{"key":"securityMeasures","label":"Security measures in place","points":6,"triggered":true,"detail":"3 of 5 measures"}]', 'claude-sonnet-4-20250514', 10009, 2261, 40587, 0, '2026-03-21T06:49:48Z');
