nsitive":false,"sourceQuote":"Uploaded image, bookmarks, comments, survey responses"}],"collectsPreciseGeolocation":{"value":true,"confidence":0.85,"sourceQuote":"If you choose to allow it, your precise location may also be processed for location-related functionality for websites like Google Maps"},"collectsBiometricData":{"value":false,"confidence":0.9,"sourceQuote":"No mention of biometric data collection such as fingerprints, face recognition, or voiceprints found in the policy"},"collectsHealthData":{"value":false,"confidence":0.9,"sourceQuote":"No mention of health, medical, fitness, or wellness data collection found in the policy"},"collectsFinancialData":{"value":false,"confidence":0.9,"sourceQuote":"No mention of financial data, payment information, bank account, or credit card collection found in the policy"}},"dataSharing":{"soldToThirdParties":{"value":false,"confidence":0.95,"sourceQuote":"What little we do know, we never sell"},"sharedForAdvertising":{"value":true,"confidence":0.9,"sourceQuote":"We also work with advertising providers to deliver relevant sponsored content using programmatic technologies. To support this, we may share limited, non-identifying information — such as device type, IP-derived location information, and category of content viewed — to help determine which ads to display"},"crossSiteTracking":{"value":false,"confidence":0.85,"sourceQuote":"Firefox protects you from known third-party trackers, social media trackers, cryptominers, cookies and fingerprinting technologies that try to follow you around the web"},"usedForProfiling":{"value":true,"confidence":0.8,"sourceQuote":"In some regions, we use this data to build models and group users based on common attributes. These groupings help us understand how people are interacting with our content and to personalize future content, including sponsored content"},"usedToTrainAI":{"value":false,"confidence":0.9,"sourceQuote":"web page content, PDFs, images and tab URLs stay on your device and are not sent to Mozilla''s servers or used for training purposes without your explicit consent"},"thirdPartyCount":5},"retention":{"retentionDays":750,"indefinite":false,"sourceQuote":"In general, we do not retain personal data for more than 25 months, but actual retention periods may vary depending on the type of data and the purpose(s) for which it was collected"},"consumerRights":{"rightToAccess":{"value":true,"confidence":0.95,"sourceQuote":"Request a copy of the data we have about you"},"rightToDelete":{"value":true,"confidence":0.95,"sourceQuote":"Have personal data we hold about you deleted (in certain circumstances)"},"rightToPortability":{"value":true,"confidence":0.95,"sourceQuote":"Request portability of your data"},"rightToCorrect":{"value":true,"confidence":0.95,"sourceQuote":"Request correction of any data we hold about you that is inaccurate or incomplete"},"rightToOptOut":{"value":true,"confidence":0.9,"sourceQuote":"You can opt out of having your data processed for personalization or advertising purposes by turning off personalization and/or sponsored content at any time"},"rightToNonDiscrimination":{"value":true,"confidence":0.95,"sourceQuote":"we will never discriminate against anyone for exercising their privacy rights"}},"signalHonoring":{"honorsGPC":{"value":true,"confidence":0.95,"sourceQuote":"Firefox also provides Global Privacy Control (GPC), which you can enable to automatically notify websites not to sell or share information about your browsing session on that website"},"honorsDNT":{"value":false,"confidence":0.4,"sourceQuote":"Policy does not mention Do Not Track (DNT) signal support. Only mentions GPC support."}},"security":{"measures":[{"name":"Encryption","sourceQuote":"We use a privacy preserving technology called OHTTP, which combines encryption and a proxy server to conceal your IP address and other identifying information"},{"name":"Safe Browsing Protection","sourceQuote":"we use Google''s Safe Browsing Service to protect you from malicious downloads and phishing attacks, and validate webpage and technical data with Certificate Authorities"},{"name":"DNS over HTTPS","sourceQuote":"Firefox routes DNS requests to a resolver service that has agreed to Mozilla''s strict privacy standards for resolvers. This provides added protection from privacy leaks to local networks and also from certain DNS security attacks"},{"name":"Secure deletion","sourceQuote":"Once the retention period expires we securely delete your data, unless otherwise required by law"},{"name":"Contractual protections","sourceQuote":"We have contractual protections in place, so that the entities receiving personal data are contractually obligated to handle the data in accordance with Mozilla''s instructions"}]}}', 91, 'A', 'Excellent', '#15803d', '1', '[{"key":"soldToThirdParties","label":"Data sold to third parties","points":0,"triggered":false},{"key":"sharedForAdvertising","label":"Data shared for advertising","points":-10,"triggered":true},{"key":"crossSiteTracking","label":"Cross-site tracking","points":0,"triggered":false},{"key":"usedForProfiling","label":"Used for profiling / AI decisions","points":-8,"triggered":true},{"key":"usedToTrainAI","label":"Used to train AI models","points":0,"triggered":false},{"key":"collectsPreciseGeolocation","label":"Collects precise geolocation","points":-8,"triggered":true},{"key":"collectsBiometricData","label":"Collects biometric data","points":0,"triggered":false},{"key":"collectsHealthData","label":"Collects health data","points":0,"triggered":false},{"key":"collectsFinancialData","label":"Collects financial data","points":0,"triggered":false},{"key":"doesNotHonorGPC","label":"Does not honor GPC","points":0,"triggered":false},{"key":"doesNotHonorDNT","label":"Does not honor DNT","points":-2,"triggered":true},{"key":"thirdPartiesOver10","label":"More than 10 third parties","points":0,"triggered":false,"detail":"5 third parties disclosed"},{"key":"thirdParties6To10","label":"6–10 