se,"sourceQuote":"We receive information from you, our Customers and other third-parties that helps us approximate your location"},{"name":"audio and video metadata","sensitive":false,"sourceQuote":"Slack may receive, capture, and store metadata derived from your use of features such as Slack Huddles or Clips"},{"name":"contact information","sensitive":false,"sourceQuote":"any contact information that an Authorized User chooses to import (such as importing an address book to find coworkers and Slack Connect contacts or calendar from a device or API)"}],"collectsPreciseGeolocation":{"value":false,"confidence":0.8,"sourceQuote":"We may, for example, use a business address submitted by your employer (who is our Customer) or an IP address received from your browser or device to determine approximate location"},"collectsBiometricData":{"value":false,"confidence":0.9,"sourceQuote":"Policy does not mention collection of fingerprints, face recognition, voiceprints, or other biometric identifiers"},"collectsHealthData":{"value":false,"confidence":0.9,"sourceQuote":"Policy does not mention collection of health, medical, fitness, or wellness data"},"collectsFinancialData":{"value":true,"confidence":0.95,"sourceQuote":"Customers that purchase a paid version of the Services provide Slack (or its payment processors) with billing details such as credit card information, banking information, and/or a billing address"}},"dataSharing":{"soldToThirdParties":{"value":false,"confidence":0.95,"sourceQuote":"Slack does not sell (as such term is defined in the CCPA or otherwise) the personal information we collect (and will not sell it without providing a right to opt out)"},"sharedForAdvertising":{"value":true,"confidence":0.9,"sourceQuote":"we may share personal information (in the form of identifiers and internet activity information) with third party advertisers for purposes of targeting advertisements on non-Slack websites, applications, and services"},"crossSiteTracking":{"value":tru