true,"confidence":0.95,"sourceQuote":"as well as to seek to update, delete, or correct this information"},"rightToOptOut":{"value":true,"confidence":0.9,"sourceQuote":"California consumers the right to request to know more details about the categories or specific pieces of personal information we collect (including how we use, disclose, or may sell this information), to delete their personal information, to opt out of any ''sales''"},"rightToNonDiscrimination":{"value":true,"confidence":0.95,"sourceQuote":"and to not be discriminated against for exercising these rights"}},"signalHonoring":{"honorsGPC":{"value":true,"confidence":0.95,"sourceQuote":"If you would like to opt-out of sharing activity based on your cookie identifiers, turn on a Global Privacy Control in your web browser or browser extension"},"honorsDNT":{"value":false,"confidence":0.7,"sourceQuote":"Policy does not mention Do Not Track (DNT) signals. Only mentions Global Privacy Control."}},"security":{"measures":[{"name":"encryption","sourceQuote":"Slack takes security of data very seriously. Slack works hard to protect Information you provide from loss, misuse, and unauthorized access or disclosure"},{"name":"security certifications","sourceQuote":"Slack has received internationally recognized security certifications"},{"name":"access controls","sourceQuote":"These steps take into account the sensitivity of the Information we collect, process and store, and the current state of technology"}]}}', 65, 'C', 'Fair', '#b45309', '1', '[{"key":"soldToThirdParties","label":"Data sold to third parties","points":0,"triggered":false},{"key":"sharedForAdvertising","label":"Data shared for advertising","points":-10,"triggered":true},{"key":"crossSiteTracking","label":"Cross-site tracking","points":-10,"triggered":true},{"key":"usedForProfiling","label":"Used for profiling / AI decisions","points":-8,"triggered":true},{"key":"usedToTrainAI","label":"Used to train AI models","points":-8,"triggered":true},{"key":"coll