INSERT OR IGNORE INTO extractions (id, policy_id, company_id, facts_json, score, letter, grade_label, grade_color, rubric_version, breakdown_json, model, input_tokens, output_tokens, latency_ms, chunked, created_at) VALUES (55, 55, 55, '{"metadata":{"schemaVersion":"1.0.0","companyName":"Dropbox (Dropbox Inc.)","policyUrl":"https://www.dropbox.com/privacy","analyzedAt":"2026-03-21T06:58:05.822Z","policyHash":"3194746ab1d0116843e1d10ea95cce37fbb47395c77045a60e4d30521c97e77f","policyEffectiveDate":"May 30, 2025"},"dataCollection":{"items":[{"name":"Account information","sensitive":false,"sourceQuote":"Account information. We collect, and associate with your account, the information you provide to us when you do things such as sign up for your account, upgrade to a paid plan, and set up two-factor authentication (like your name, email address, phone number, payment info, and physical address)."},{"name":"Your Stuff","sensitive":false,"sourceQuote":"Our Services are designed as a simple and personalized way for you to store your files, documents, photos, comments, messages, data from connected services, and so on (''Your Stuff'')"},{"name":"Contacts","sensitive":false,"sourceQuote":"You may choose to give us access to your contacts to make it easy for you, and your Dropbox Team if you''re a Dropbox Team user, to do things like share and collaborate on Your Stuff"},{"name":"Usage information","sensitive":false,"sourceQuote":"We collect information related to how you use the Services, including actions you take in your account (like sharing, editing, viewing, creating and moving files or folders, and sending and receiving electronic signature requests and other transactions)."},{"name":"Device information","sensitive":false,"sourceQuote":"We also collect information from and about the devices you use to access the Services. This includes things like IP addresses, the type of browser and device you use, the web page you visited before coming to our sites, and identifiers associated with your devices."},{"name":"Location information","sensitive":true,"sourceQuote":"Your devices (depending on their settings) may also transmit location information to the Services."},{"name":"Payment info","sensitive":true,"sourceQuote":"like your name, email address, phone number, payment info, and physical address"},{"name":"Cookies and tracking data","sensitive":false,"sourceQuote":"We use technologies like cookies and pixel tags to provide, improve, protect, and promote our Services."},{"name":"Recipient and viewer analytics","sensitive":false,"sourceQuote":"When you view content included in portions of our Services that provide analytics to content owners, we collect information including your identifying and device information, such as email addresses, IP addresses, and device identifiers of devices you use to view the content."}],"collectsPreciseGeolocation":{"value":false,"confidence":0.7,"sourceQuote":"Your devices (depending on their settings) may also transmit location information to the Services."},"collectsBiometricData":{"value":false,"confidence":0.9,"sourceQuote":"Policy does not mention collection of biometric data such as fingerprints, face recognition, or voiceprints."},"collectsHealthData":{"value":false,"confidence":0.9,"sourceQuote":"Policy does not mention collection of health, medical, fitness, or wellness data."},"collectsFinancialData":{"value":true,"confidence":0.9,"sourceQuote":"like your name, email address, phone number, payment info, and physical address"}},"dataSharing":{"soldToThirdParties":{"value":false,"confidence":0.95,"sourceQuote":"We may share information as discussed below, but we won''t sell it to advertisers or other third parties."},"sharedForAdvertising":{"value":true,"confidence":0.8,"sourceQuote":"We may also use third-party service providers that set cookies and similar technologies to promote Dropbox services."},"crossSiteTracking":{"value":true,"confidence":0.8,"sourceQuote":"We may also use third-party service providers that set cookies and similar technologies to promote Dropbox services."},"usedForProfiling":{"value":true,"confidence":0.7,"sourceQuote":"For example, if you interact with a person at a company, and that person frequently works with one of their coworkers, we may suggest you as a potential collaborator for that coworker."},"usedToTrainAI":{"value":true,"confidence":0.8,"sourceQuote":"For more information on the lawful bases for processing your data, the categories of personal information included, and how we use artificial intelligence and machine learning, please see our FAQ."},"thirdPartyCount":null},"retention":{"retentionDays":null,"indefinite":true,"sourceQuote":"When you sign up for an account with us, we''ll retain information you store on our Services for as long as your account exists or as long as we need it to provide you the Services. If you delete your account, we''ll initiate deletion of this information after 30 days."},"consumerRights":{"rightToAccess":{"value":true,"confidence":0.95,"sourceQuote":"You can access your personal data from your Dropbox account and you can download a copy of Your Stuff in a machine readable format as outlined here."},"rightToDelete":{"value":true,"confidence":0.95,"sourceQuote":"Delete Your Stuff in your Dropbox account. You can learn more about how to delete files saved on Dropbox here."},"rightToPortability":{"value":true,"confidence":0.95,"sourceQuote":"Access and take your data elsewhere. You can access your personal data from your Dropbox account and you can download a copy of Your Stuff in a machine readable format as outlined here."},"rightToCorrect":{"value":true,"confidence":0.95,"sourceQuote":"Change or correct personal data. You can manage your account and the content contained in it, as well as edit some of your personal data, through your account settings page."},"rightToOptOut":{"value":true,"confidence":0.9,"sourceQuote":"Object to the processing of your personal data. Depending on the processing activity, you can request that we stop or limit processing of your personal data."},"rightToNonDiscrimination":{"value":false,"confidence":0.4,"sourceQuote":"Policy does not explicitly mention right to non-discrimination for exercising privacy rights."}},"signalHonoring":{"honorsGPC":{"value":false,"confidence":0.4,"sourceQuote":"Policy does not mention Global Privacy Control (GPC). Defaulting to not honored."},"honorsDNT":{"value":true,"confidence":0.9,"sourceQuote":"If our systems receive a DNT:1 signal from your browser, we''ll respond to that signal as outlined here."}},"security":{"measures":[{"name":"Two-factor authentication","sourceQuote":"We continue to work on features to keep your information safe in addition to things like two-factor authentication, encryption of files at rest, and alerts when new devices and apps are linked to your account."},{"name":"Encryption of files at rest","sourceQuote":"We continue to work on features to keep your information safe in addition to things like two-factor authentication, encryption of files at rest, and alerts when new devices and apps are linked to your account."},{"name":"Device and app alerts","sourceQuote":"We continue to work on features to keep your information safe in addition to things like two-factor authentication, encryption of files at rest, and alerts when new devices and apps are linked to your account."},{"name":"Automated abuse detection","sourceQuote":"We deploy automated technologies to detect abusive behavior and content that may harm our Services, you, or other users."},{"name":"Vulnerability testing","sourceQuote":"We have a team dedicated to keeping your information secure and testing for vulnerabilities."}]}}', 66, 'C', 'Fair', '#b45309', '1', '[{"key":"soldToThirdParties","label":"Data sold to third parties","points":0,"triggered":false},{"key":"sharedForAdvertising","label":"Data shared for advertising","points":-10,"triggered":true},{"key":"crossSiteTracking","label":"Cross-site tracking","points":-10,"triggered":true},{"key":"usedForProfiling","label":"Used for profiling / AI decisions","points":-8,"triggered":true},{"key":"usedToTrainAI","label":"Used to train AI models","points":-8,"triggered":true},{"key":"collectsPreciseGeolocation","label":"Collects precise geolocation","points":0,"triggered":false},{"key":"collectsBiometricData","label":"Collects biometric data","points":0,"triggered":false},{"key":"collectsHealthData","label":"Collects health data","points":0,"triggered":false},{"key":"collectsFinancialData","label":"Collects financial data","points":-3,"triggered":true},{"key":"doesNotHonorGPC","label":"Does not honor GPC","points":-5,"triggered":true},{"key":"doesNotHonorDNT","label":"Does not honor DNT","points":0,"triggered":false},{"key":"thirdPartiesOver10","label":"More than 10 third parties","points":0,"triggered":false},{"key":"thirdParties6To10","label":"6–10 third parties","points":0,"triggered":false},{"key":"retentionIndefinite","label":"Retention is indefinite","points":-10,"triggered":true},{"key":"retentionOver3Years","label":"Retention longer than 3 years","points":0,"triggered":false},{"key":"retentionOver1Year","label":"Retention longer than 1 year","points":0,"triggered":false},{"key":"consumerRights","label":"Consumer rights available","points":10,"triggered":true,"detail":"5 of 6 rights offered"},{"key":"securityMeasures","label":"Security measures in place","points":10,"triggered":true,"detail":"5 of 5 measures"}]', 'claude-sonnet-4-20250514', 6554, 2086, 25751, 0, '2026-03-21T06:58:31Z');
