":0.85,"sourceQuote":"This kind of sharing may be considered a ''sale'' of personal information or the use of personal information to serve ''targeted advertising'' under certain privacy laws"},"sharedForAdvertising":{"value":true,"confidence":0.95,"sourceQuote":"to provide personalized and/or generalized advertising and direct marketing communications, promotions, and offers that might interest you relating to Samsung''s and our partners'' products and Services"},"crossSiteTracking":{"value":true,"confidence":0.9,"sourceQuote":"These networks can track users'' online activities over time by collecting information through automated means, including through the use of browser cookies, web beacons, pixels, device identifiers, server logs"},"usedForProfiling":{"value":true,"confidence":0.85,"sourceQuote":"Ad networks allow us to target our messaging to users considering demographic data, users'' inferred interests, and browsing context"},"usedToTrainAI":{"value":true,"confidence":0.95,"sourceQuote":"we may also use personal information about United States residents for other purposes, such as to develop and train our artificial intelligence algorithms and models"},"thirdPartyCount":null},"retention":{"retentionDays":null,"indefinite":false,"sourceQuote":"We will not keep your personal information for longer than is necessary for the purpose for which it was collected. This means that information will be destroyed or erased from our systems when it is no longer required."},"consumerRights":{"rightToAccess":{"value":true,"confidence":0.95,"sourceQuote":"You have the right to ask us to provide details about what we have collected and to provide your personal information to you in a structured, commonly used and machine-readable format"},"rightToDelete":{"value":true,"confidence":0.95,"sourceQuote":"You have the right to ask us to provide details about what we have collected and to provide your personal information to you in a structured, commonly used and machine-readable format, to delete it"},"rightToPortability":{"value":true,"confidence":0.95,"sourceQuote":"You have the right to data portability, which means you can ask us to provide your personal information to you or a third party in a machine-readable format"},"rightToCorrect":{"value":true,"confidence":0.95,"sourceQuote":"You have the right to ask us to provide details about what we have collected and to provide your personal information to you in a structured, commonly used and machine-readable format, to delete it, or correct any inaccuracies"},"rightToOptOut":{"value":true,"confidence":0.95,"sourceQuote":"you may also, subject to applicable law, request to opt out of the (1) sale of your personal information, (2) sharing of your personal information for cross-context behavioral advertising purposes"},"rightToNonDiscrimination":{"value":false,"confidence":0.4,"sourceQuote":"Policy does not explicitly mention right to non-discrimination. Defaulting to false with low confidence."}},"signalHonoring":{"honorsGPC":{"value":false,"confidence":0.4,"sourceQuote":"Policy does not mention Global Privacy Control (GPC). Defaulting to not honored."},"honorsDNT":{"value":false,"confidence":0.8,"sourceQuote":"We do not respond to browser-based signals that do not meet applicable state law requirements, which may include older Do Not Track signals"}},"security":{"measures":[{"name":"Physical safeguards","sourceQuote":"We have put in place physical and technical safeguards to keep your information secure"},{"name":"Technical safeguards","sourceQuote":"We have put in place physical and technical safeguards to keep your information secure"},{"name":"Standard contractual clauses","sourceQuote":"The measures we take to safeguard the transfer of your information include the use of standard contractual clauses as approved by the relevant data protection authority"}]}}', 24, 'F', 'Failing', '#b91c1c', '1', '[{"key":"soldToThirdParties","label":"Data sold to third parties","points":-25,"triggered"