d devices that use our advertising services"},"usedForProfiling":{"value":true,"confidence":0.95,"sourceQuote":"Our systems automatically process information we''ve collected and stored associated with you and others to assess and understand your interests and your preferences and provide you personalized experiences... apply automated processing techniques and, in some cases, also manual (human) reviewing, to... profiling"},"usedToTrainAI":{"value":true,"confidence":0.9,"sourceQuote":"Develop and improve AI at Meta for Meta Products and for third parties... We use information we have, information from researchers and datasets from publicly available sources... to conduct and support research"},"thirdPartyCount":null},"retention":{"retentionDays":null,"indefinite":true,"sourceQuote":"We keep information as long as we need it to provide our Products, comply with legal obligations or protect our or other''s interests. We decide how long we need information on a case-by-case basis... In some instances and for specific reasons, we''ll keep information for an extended period of time"},"consumerRights":{"rightToAccess":{"value":true,"confidence":0.9,"sourceQuote":"We offer you a variety of tools to view, manage, download and delete your information below... Access your information"},"rightToDelete":{"value":true,"confidence":0.9,"sourceQuote":"We offer you a variety of tools to view, manage, download and delete your information below... Delete your information or account"},"rightToPortability":{"value":true,"confidence":0.9,"sourceQuote":"Port, download or delete your information... Port your information"},"rightToCorrect":{"value":true,"confidence":0.8,"sourceQuote":"We offer you a variety of tools to view, manage, download and delete your information below. You can also manage your information by visiting the settings"},"rightToOptOut":{"value":true,"confidence":0.8,"sourceQuote":"You can learn more about the consumer privacy rights that may be available to you by reviewing the United States Regional Privacy Notice"},"rightToNonDiscrimination":{"value":true,"confidence":0.7,"sourceQuote":"You can learn more about the consumer privacy rights that may be available to you by reviewing the United States Regional Privacy Notice"}},"signalHonoring":{"honorsGPC":{"value":false,"confidence":0.4,"sourceQuote":"Policy does not mention Global Privacy Control (GPC). Defaulting to not honored."},"honorsDNT":{"value":false,"confidence":0.4,"sourceQuote":"Policy does not mention Do Not Track (DNT). Defaulting to not honored."}},"security":{"measures":[{"name":"Automated and manual review processes","sourceQuote":"The information we use for these purposes is automatically processed by our systems. But in some cases, we also use manual review to access and review your information"},{"name":"Safety and security verification","sourceQuote":"Verify accounts and activity, Find and address violations of our terms or policies... Detect, prevent and combat harmful or unlawful behavior"},{"name":"Global data transfer safeguards","sourceQuote":"How do we safeguard your information?"}]}}', 49, 'D', 'Poor', '#c2410c', '1', '[{"key":"soldToThirdParties","label":"Data sold to third parties","points":0,"triggered":false},{"key":"sharedForAdvertising","label":"Data shared for advertising","points":-10,"triggered":true},{"key":"crossSiteTracking","label":"Cross-site tracking","points":-10,"triggered":true},{"key":"usedForProfiling","label":"Used for profiling / AI decisions","points":-8,"triggered":true},{"key":"usedToTrainAI","label":"Used to train AI models","points":-8,"triggered":true},{"key":"collectsPreciseGeolocation","label":"Collects precise geolocation","points":-8,"triggered":true},{"key":"collectsBiometricData","label":"Collects biometric data","points":0,"triggered":false},{"key":"collectsHealthData","label":"Collects health data","points":-5,"triggered":true},{"key":"collectsFinancialData","label":"Collects financial data","points":-3,"triggered":tr