INSERT OR IGNORE INTO extractions (id, policy_id, company_id, facts_json, score, letter, grade_label, grade_color, rubric_version, breakdown_json, model, input_tokens, output_tokens, latency_ms, chunked, created_at) VALUES (71, 71, 71, '{"metadata":{"schemaVersion":"1.0.0","companyName":"DoorDash","policyUrl":"https://help.doordash.com/legal/document?type=cx-privacy-policy&region=US&locale=en-US","analyzedAt":"2026-03-26T23:16:30.503Z","policyHash":"81aa7c5f1c25bda6c58ea6102ffae6bcae9ec2c3b8c43e782c4e862f3cfca002","policyEffectiveDate":"July 1, 2025"},"dataCollection":{"items":[{"name":"Contact Information","sensitive":false,"sourceQuote":"Contact Information, including name, address (such as home address, work address, or other delivery address), email address(es), phone number(s), and other contact information provided to us."},{"name":"Account and Profile Information","sensitive":false,"sourceQuote":"Account and Profile Information, including username and credentials, privacy settings and notification preferences, pictures, and other information you add to your DoorDash profile"},{"name":"Government ID and Signatures","sensitive":true,"sourceQuote":"Identification Documentation and Signature for Age-Restricted Products, including driver''s license or other government issued identification documents"},{"name":"Communications","sensitive":false,"sourceQuote":"Communications with DoorDash, Dashers and Merchants, including the content of in-app messages with Dashers, communications with Merchants through or in-connection with our Services"},{"name":"Payment Information","sensitive":true,"sourceQuote":"Payment Information, including credit card or debit card information and information about the payment methods and services (such as PayPal or Venmo) used to make purchases"},{"name":"Activity and Transactions","sensitive":false,"sourceQuote":"Activity and Transactions on or with our Services, including information about the items and products ordered, order history, items placed in the cart, special instructions included in an order"},{"name":"Precise Geolocation","sensitive":true,"sourceQuote":"Geolocation Information, if you have consented by enabling location access, we may receive and store your precise location information"},{"name":"Device Information","sensitive":false,"sourceQuote":"Device Information, including information about the computers, phones, and other devices you use to interact with DoorDash or our Services, internet-protocol address, device-based identifiers"},{"name":"Health Data","sensitive":true,"sourceQuote":"Personal Information that may identify your past, present, or future physical or mental health status (''Consumer Health Data''), where applicable"}],"collectsPreciseGeolocation":{"value":true,"confidence":0.95,"sourceQuote":"Geolocation Information, if you have consented by enabling location access, we may receive and store your precise location information, including when our apps are running in the foreground (our app is open and on screen) or background (our app is open, not on screen) of your device."},"collectsBiometricData":{"value":false,"confidence":0.85,"sourceQuote":"Policy does not mention collection of fingerprints, face recognition, voiceprints, or retina scans. No biometric data collection is described."},"collectsHealthData":{"value":true,"confidence":0.9,"sourceQuote":"We collect Personal Information as described in Section II (What Personal Information does DoorDash collect or process) of this Policy, which may include the following Consumer Health Data about you or those you are purchasing on behalf of: Allergies or other conditions... Product Purchase Information: Your purchase history of health-related products ordered through our Services may indicate information regarding your health status, including, but not limited to, contraceptives, at-home diagnostic tests, and diabetic testing supplies."},"collectsFinancialData":{"value":true,"confidence":0.95,"sourceQuote":"Payment Information, including credit card or debit card information and information about the payment methods and services (such as PayPal or Venmo) used to make purchases on or through our Services."}},"dataSharing":{"soldToThirdParties":{"value":true,"confidence":0.8,"sourceQuote":"We may disclose Personal Information (e.g., identifiers and service and platform usage) to advertising partners to provide you with personalized ads on third-party platforms, which may constitute a ''sale'' or ''sharing'' of your Personal Information."},"sharedForAdvertising":{"value":true,"confidence":0.9,"sourceQuote":"To Marketing and Advertising Partners: We may use third-party marketing and advertising partners to deliver advertising to you on behalf of DoorDash and/or our Merchants, including advertising that may be personalized based on your interactions with our Services as well as your activity on third-party services."},"crossSiteTracking":{"value":true,"confidence":0.7,"sourceQuote":"Through Cookies and Similar Technologies: Cookies are small text files that are placed on your device, commonly through your browser, and that are used to record information such as settings. Depending on your settings, certain of our Services, including our website, may receive information about you from or through cookies or similar technologies (such as pixels or software development kits)."},"usedForProfiling":{"value":true,"confidence":0.85,"sourceQuote":"To Provide and Customize DoorDash Services, including allowing you to place and pay for orders, facilitating the orders you place on or through our Services, recommending and ranking Merchants based on your searches, location, reviews and order history... customizing your experience (including, but not limited to, customization based on your preferences, location, and past use of our Services)."},"usedToTrainAI":{"value":false,"confidence":0.6,"sourceQuote":"Policy mentions ''improve the Services'' and ''developing new Services'' but does not explicitly mention AI training or machine learning model training."},"thirdPartyCount":null},"retention":{"retentionDays":null,"indefinite":false,"sourceQuote":"We retain your Personal Information for only as long as required to provide our Services to you and engage in the uses described in this Policy, unless a different retention period is required by applicable law."},"consumerRights":{"rightToAccess":{"value":true,"confidence":0.95,"sourceQuote":"Access/Portability: You may have the right to request access to your Personal Information (including which third parties have received Personal Information) and receive it in a portable and machine-readable format."},"rightToDelete":{"value":true,"confidence":0.95,"sourceQuote":"Deletion: You may have the right to ask us to delete your Personal Information, including your DoorDash account, although this may impact your ability to use the Services."},"rightToPortability":{"value":true,"confidence":0.95,"sourceQuote":"Access/Portability: You may have the right to request access to your Personal Information (including which third parties have received Personal Information) and receive it in a portable and machine-readable format."},"rightToCorrect":{"value":true,"confidence":0.95,"sourceQuote":"Correction: You may have the right to correct, rectify, or update inaccurate Personal Information that we hold about you."},"rightToOptOut":{"value":true,"confidence":0.95,"sourceQuote":"Opt-Out of Sale or Sharing (Targeted Advertising or Ads Personalization): We may disclose Personal Information (e.g., identifiers and service and platform usage) to advertising partners to provide you with personalized ads on third-party platforms, which may constitute a ''sale'' or ''sharing'' of your Personal Information. You have the right to opt-out of our selling or sharing (for purposes of targeted advertising) of your Personal Information."},"rightToNonDiscrimination":{"value":true,"confidence":0.95,"sourceQuote":"DoorDash will not discriminate against you for exercising any of your applicable rights."}},"signalHonoring":{"honorsGPC":{"value":true,"confidence":0.9,"sourceQuote":"You may choose to enable with your browser, where available, global privacy controls (''GPC'') to automatically communicate your opt-out preferences to us when you use said browser. If you have enabled GPC on your browser, we will treat this the same as if you have opted-out through the browser-level opt-out option available above."},"honorsDNT":{"value":false,"confidence":0.8,"sourceQuote":"Policy mentions GPC but does not mention Do Not Track (DNT) signals. Only GPC is explicitly supported."}},"security":{"measures":[{"name":"Administrative Controls","sourceQuote":"We use commercially reasonable administrative, organizational, technical and physical security controls to protect your Personal Information from unauthorized access, modification, disclosure, or destruction."},{"name":"Technical Controls","sourceQuote":"We use commercially reasonable administrative, organizational, technical and physical security controls to protect your Personal Information from unauthorized access, modification, disclosure, or destruction."},{"name":"Physical Controls","sourceQuote":"We use commercially reasonable administrative, organizational, technical and physical security controls to protect your Personal Information from unauthorized access, modification, disclosure, or destruction."},{"name":"Organizational Controls","sourceQuote":"We use commercially reasonable administrative, organizational, technical and physical security controls to protect your Personal Information from unauthorized access, modification, disclosure, or destruction."}]}}', 49, 'D', 'Poor', '#c2410c', '1', '[{"key":"soldToThirdParties","label":"Data sold to third parties","points":-25,"triggered":true},{"key":"sharedForAdvertising","label":"Data shared for advertising","points":-10,"triggered":true},{"key":"crossSiteTracking","label":"Cross-site tracking","points":-10,"triggered":true},{"key":"usedForProfiling","label":"Used for profiling / AI decisions","points":-8,"triggered":true},{"key":"usedToTrainAI","label":"Used to train AI models","points":0,"triggered":false},{"key":"collectsPreciseGeolocation","label":"Collects precise geolocation","points":-8,"triggered":true},{"key":"collectsBiometricData","label":"Collects biometric data","points":0,"triggered":false},{"key":"collectsHealthData","label":"Collects health data","points":-5,"triggered":true},{"key":"collectsFinancialData","label":"Collects financial data","points":-3,"triggered":true},{"key":"doesNotHonorGPC","label":"Does not honor GPC","points":0,"triggered":false},{"key":"doesNotHonorDNT","label":"Does not honor DNT","points":-2,"triggered":true},{"key":"thirdPartiesOver10","label":"More than 10 third parties","points":0,"triggered":false},{"key":"thirdParties6To10","label":"6–10 third parties","points":0,"triggered":false},{"key":"retentionIndefinite","label":"Retention is indefinite","points":0,"triggered":false},{"key":"retentionOver3Years","label":"Retention longer than 3 years","points":0,"triggered":false},{"key":"retentionOver1Year","label":"Retention longer than 1 year","points":0,"triggered":false},{"key":"consumerRights","label":"Consumer rights available","points":12,"triggered":true,"detail":"6 of 6 rights offered"},{"key":"securityMeasures","label":"Security measures in place","points":8,"triggered":true,"detail":"4 of 5 measures"}]', 'claude-sonnet-4-20250514', 12272, 2415, 45493, 0, '2026-03-26T23:17:15Z');

