geted advertising based on your activity on our sites and applications and on third-party sites and applications"},"crossSiteTracking":{"value":true,"confidence":0.9,"sourceQuote":"We collect information through a variety of technologies, such as cookies, Flash cookies, pixels, tags, software development kits, application program interfaces, and Web beacons, including when you visit our sites and applications or use our applications on third-party sites or platforms"},"usedForProfiling":{"value":true,"confidence":0.85,"sourceQuote":"Personalize content and experiences"},"usedToTrainAI":{"value":false,"confidence":0.6,"sourceQuote":"Policy does not explicitly mention using personal information to train AI or machine learning models"},"thirdPartyCount":null},"retention":{"retentionDays":null,"indefinite":false,"sourceQuote":"We will retain your personal information for the length of time needed to fulfill the purposes outlined in this privacy policy unless a longer retention period is required or permitted by law"},"consumerRights":{"rightToAccess":{"value":true,"confidence":0.95,"sourceQuote":"request to know about and obtain access to the personal information we have collected about you"},"rightToDelete":{"value":true,"confidence":0.95,"sourceQuote":"request that we delete the personal information we have collected about you, subject to applicable legal exceptions"},"rightToPortability":{"value":false,"confidence":0.7,"sourceQuote":"Policy does not explicitly mention data portability rights"},"rightToCorrect":{"value":true,"confidence":0.9,"sourceQuote":"request to update or correct your personal information"},"rightToOptOut":{"value":true,"confidence":0.95,"sourceQuote":"request to opt out of targeted advertising and/or the sale or sharing of your personal information"},"rightToNonDiscrimination":{"value":true,"confidence":0.9,"sourceQuote":"you may have certain rights with respect to your personal information or personal data, which include the right not to be discriminated against (as provided for under applicable law) for exercising your rights"}},"signalHonoring":{"honorsGPC":{"value":true,"confidence":0.9,"sourceQuote":"We will process the GPC signal as a request to opt out"},"honorsDNT":{"value":false,"confidence":0.7,"sourceQuote":"Policy does not mention Do Not Track (DNT) signals"}},"security":{"measures":[{"name":"Technical security measures","sourceQuote":"We have implemented technical, administrative, and physical security measures that are designed to protect guest information from unauthorized access, disclosure, use, and modification"},{"name":"Regular security reviews","sourceQuote":"We regularly review our security procedures to consider appropriate new technology and methods"}]}}', 48, 'D', 'Poor', '#c2410c', '1', '[{"key":"soldToThirdParties","label":"Data sold to third parties","points":-25,"triggered":true},{"key":"sharedForAdvertising","label":"Data shared for advertising","points":-10,"triggered":true},{"key":"crossSiteTracking","label":"Cross-site tracking","points":-10,"triggered":true},{"key":"usedForProfiling","label":"Used for profiling / AI decisions","points":-8,"triggered":true},{"key":"usedToTrainAI","label":"Used to train AI models","points":0,"triggered":false},{"key":"collectsPreciseGeolocation","label":"Collects precise geolocation","points":-8,"triggered":true},{"key":"collectsBiometricData","label":"Collects biometric data","points":0,"triggered":false},{"key":"collectsHealthData","label":"Collects health data","points":0,"triggered":false},{"key":"collectsFinancialData","label":"Collects financial data","points":-3,"triggered":true},{"key":"doesNotHonorGPC","label":"Does not honor GPC","points":0,"triggered":false},{"key":"doesNotHonorDNT","label":"Does not honor DNT","points":-2,"triggered":true},{"key":"thirdPartiesOver10","label":"More than 10 third parties","points":0,"triggered":false},{"key":"thirdParties6To10","label":"6–10 third parties","points":0,"triggered":false},{"key":"rete