INSERT OR IGNORE INTO extractions (id, policy_id, company_id, facts_json, score, letter, grade_label, grade_color, rubric_version, breakdown_json, model, input_tokens, output_tokens, latency_ms, chunked, created_at) VALUES (97, 97, 97, '{"metadata":{"schemaVersion":"1.0.0","companyName":"Duolingo (Duolingo Inc.)","policyUrl":"https://www.duolingo.com/privacy","analyzedAt":"2026-03-26T23:23:34.937Z","policyHash":"dab63f4443387fdbc8b5b65fef43194ad0b77517f647737c35a41ef31ca44f5a","policyEffectiveDate":"January 5, 2026"},"dataCollection":{"items":[{"name":"username","sensitive":false,"sourceQuote":"To register for a Duolingo account, you may provide us with a username, your age and email address."},{"name":"age","sensitive":false,"sourceQuote":"To register for a Duolingo account, you may provide us with a username, your age and email address."},{"name":"email address","sensitive":false,"sourceQuote":"To register for a Duolingo account, you may provide us with a username, your age and email address."},{"name":"phone number","sensitive":false,"sourceQuote":"In some countries, you may also provide us with your phone number."},{"name":"name","sensitive":false,"sourceQuote":"Your Profile will be populated by information you submit, such as your name, bio, and profile picture"},{"name":"bio","sensitive":false,"sourceQuote":"Your Profile will be populated by information you submit, such as your name, bio, and profile picture"},{"name":"profile picture","sensitive":false,"sourceQuote":"Your Profile will be populated by information you submit, such as your name, bio, and profile picture"},{"name":"learning progress","sensitive":false,"sourceQuote":"Your Profile will also include information about your learning progress, such as the languages you are learning, your learning statistics, and your achievements."},{"name":"audio recordings","sensitive":true,"sourceQuote":"Duolingo may generate, record, and store audio recordings or transcripts of the text and audio you submit"},{"name":"contacts","sensitive":true,"sourceQuote":"give the Duolingo app permission to access the contacts stored on your phone, including the phone number, name, photo, and other information stored in that contact"},{"name":"IP address","sensitive":false,"sourceQuote":"we may generate data about your use of the Service, which may include your browser and device data, log data, and IP address"},{"name":"browser and device data","sensitive":false,"sourceQuote":"we may generate data about your use of the Service, which may include your browser and device data, log data, and IP address"},{"name":"usage patterns","sensitive":false,"sourceQuote":"FullStory records usage patterns (e.g., clicks, mouse movements, scrolling, and typing)"},{"name":"cookies","sensitive":false,"sourceQuote":"When you access the Duolingo website, we store certain data from your browser using cookies."}],"collectsPreciseGeolocation":{"value":false,"confidence":0.8,"sourceQuote":"Policy does not mention GPS or precise location data collection, only mentions IP addresses which provide approximate location."},"collectsBiometricData":{"value":false,"confidence":0.9,"sourceQuote":"Policy does not mention fingerprint, face recognition, voiceprint, or retina scanning."},"collectsHealthData":{"value":false,"confidence":0.9,"sourceQuote":"Policy does not mention health, medical, fitness, or wellness data collection."},"collectsFinancialData":{"value":false,"confidence":0.85,"sourceQuote":"Policy mentions payment processors like Stripe but does not specify collection of financial data by Duolingo itself."}},"dataSharing":{"soldToThirdParties":{"value":false,"confidence":0.4,"sourceQuote":"Policy does not explicitly mention selling data, but extensively describes sharing with third parties. Defaulting to consumer-unfavorable interpretation due to ambiguity."},"sharedForAdvertising":{"value":true,"confidence":0.95,"sourceQuote":"Duolingo may process and share your personal information for the purpose of providing you with personalized advertising. To provide personalized advertising, we work with a variety of third-party advertising networks, marketing analytics service providers, and website analysis firms, such as Google, Meta, Oath, and Unity."},"crossSiteTracking":{"value":true,"confidence":0.9,"sourceQuote":"These third-party advertising service providers collect and use personal information about your visits to and use of the Service, as well as other websites, in order to serve you with advertisements and content tailored to meet your preferences"},"usedForProfiling":{"value":true,"confidence":0.9,"sourceQuote":"serve you with advertisements and content tailored to meet your preferences and likely interests"},"usedToTrainAI":{"value":true,"confidence":0.95,"sourceQuote":"use these recordings or transcripts for product improvement and personalization purposes, including training and running Duolingo''s own artificial intelligence models"},"thirdPartyCount":12},"retention":{"retentionDays":null,"indefinite":true,"sourceQuote":"To ensure your account stays operational, Duolingo will generally retain your personal information until your account is deleted. However, Duolingo may retain certain information longer if necessary to provide our Service, defend our legitimate interests or those of third parties, comply with legal requirements, resolve or defend ourselves in disputes, investigate misuse or disruption of the Service, or perform agreements. We may also retain anonymous data indefinitely."},"consumerRights":{"rightToAccess":{"value":true,"confidence":0.95,"sourceQuote":"Access a copy of the personal information that we hold about you."},"rightToDelete":{"value":true,"confidence":0.95,"sourceQuote":"Request that we delete any personal information we have collected from you."},"rightToPortability":{"value":true,"confidence":0.95,"sourceQuote":"Export the personal information you have provided to Duolingo in a format that can be transferred electronically to a third party."},"rightToCorrect":{"value":true,"confidence":0.95,"sourceQuote":"Request that we correct any inaccurate personal information about you."},"rightToOptOut":{"value":true,"confidence":0.95,"sourceQuote":"Opt out of the sharing of your personal information with third parties."},"rightToNonDiscrimination":{"value":true,"confidence":0.95,"sourceQuote":"Not be discriminated against for exercising your data subject rights."}},"signalHonoring":{"honorsGPC":{"value":false,"confidence":0.4,"sourceQuote":"Policy does not mention Global Privacy Control (GPC). Defaulting to not honored."},"honorsDNT":{"value":false,"confidence":0.95,"sourceQuote":"The Service is not designed to respond to ''do not track'' signals sent by some browsers."}},"security":{"measures":[{"name":"Encrypted hashing for contact phone numbers","sourceQuote":"Duolingo will not store your contacts'' phone numbers, but only an encrypted ''hash'' of them. This hash is an alternative code to the actual phone number and can be used only to match the hash of other users'' numbers."},{"name":"Data Privacy Framework compliance","sourceQuote":"Duolingo complies with the EU-U.S. Data Privacy Framework (EU-U.S. DPF), the UK Extension to the EU-U.S. DPF, and the Swiss-U.S. Data Privacy Framework (Swiss-U.S. DPF)"}]}}', 53, 'D', 'Poor', '#c2410c', '1', '[{"key":"soldToThirdParties","label":"Data sold to third parties","points":0,"triggered":false},{"key":"sharedForAdvertising","label":"Data shared for advertising","points":-10,"triggered":true},{"key":"crossSiteTracking","label":"Cross-site tracking","points":-10,"triggered":true},{"key":"usedForProfiling","label":"Used for profiling / AI decisions","points":-8,"triggered":true},{"key":"usedToTrainAI","label":"Used to train AI models","points":-8,"triggered":true},{"key":"collectsPreciseGeolocation","label":"Collects precise geolocation","points":0,"triggered":false},{"key":"collectsBiometricData","label":"Collects biometric data","points":0,"triggered":false},{"ke